func TestAlertPriorityRank(t *testing.T) {
	tests := []struct {
		priority string
		want     int
	}{
		{"critical", 0},
		{"Critical", 0},
		{"high", 1},
		{"error", 1},
		{"medium", 2},
		{"warning", 2},
		{"low", 3},
		{"info", 3},
		{"", 4},
		{"bogus", 4},
		{"  HIGH  ", 1},
	}
	for _, tt := range tests {
		if got := alertPriorityRank(tt.priority); got != tt.want {
			t.Fatalf("alertPriorityRank(%q) = %d, want %d", tt.priority, got, tt.want)
		}
	}
}

func TestAlertTriageGroupsByClient(t *testing.T) {
	dbPath := seedNovelStore(t)
	out := runNovelCmd(t, newNovelAlertTriageCmd, "--group-by", "client", "--db", dbPath)

	var report alertTriageReport
	mustUnmarshal(t, out, &report)

	if report.TotalAlerts != 3 {
		t.Fatalf("TotalAlerts = %d, want 3", report.TotalAlerts)
	}
	if len(report.Groups) != 2 {
		t.Fatalf("Groups = %+v, want 2 clients", report.Groups)
	}
	// Acme Corp (3 alerts) must rank above Globex (0).
	if report.Groups[0].Group != "Acme Corp" || report.Groups[0].OpenAlerts != 3 {
		t.Fatalf("top group = %+v, want Acme Corp with 3 alerts", report.Groups[0])
	}
	if report.Groups[1].OpenAlerts != 0 {
		t.Fatalf("Globex should have 0 alerts, got %+v", report.Groups[1])
	}
}

